SELECT * FROM sys_operation_log


        AND user_id = #{params.userId}


        AND username LIKE CONCAT('%', #{params.username}, '%')


        AND module_name = #{params.moduleName}


        AND operation_type = #{params.operationType}


        AND status = #{params.status}


        AND create_time >= #{params.startTime}


        AND create_time <= #{params.endTime}


        AND (operation_desc LIKE CONCAT('%', #{params.keyword}, '%')
             OR request_url LIKE CONCAT('%', #{params.keyword}, '%'))


ORDER BY create_time DESC

    LIMIT #{params.offset}, #{params.pageSize}

SELECT COUNT(*) FROM sys_operation_log


        AND user_id = #{params.userId}


